import React, { useEffect, useState } from "react";
import api from "../../api/axios";
import toast from "react-hot-toast";
import "../admin/Admin.css";

export default function TeacherClasses() {
  const [classes, setClasses] = useState([]);
  const [selected, setSelected] = useState(null);
  const [students, setStudents] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    api.get("/teacher/classes")
      .then(r => setClasses(r.data.data || []))
      .catch(() => toast.error("Không thể tải dữ liệu"))
      .finally(() => setLoading(false));
  }, []);

  const viewStudents = async (cls) => {
    setSelected(cls);
    try {
      const r = await api.get(`/teacher/classes/${cls.id}/students`);
      setStudents(r.data.data || []);
    } catch { toast.error("Không thể tải danh sách học viên"); }
  };

  return (
    <div className="admin-page fade-in">
      <div className="page-header">
        <h1>Lớp học của tôi</h1>
        <p>Các lớp bạn đang được phân công giảng dạy</p>
      </div>

      <div style={{ display: "grid", gridTemplateColumns: selected ? "1fr 1fr" : "1fr", gap: 20 }}>
        <div className="table-wrapper">
          {loading ? <div className="page-loading"><div className="spinner" /></div> : (
            <table className="data-table">
              <thead><tr><th>Tên lớp</th><th>Sĩ số</th><th>Trạng thái</th><th>Thao tác</th></tr></thead>
              <tbody>
                {classes.length === 0
                  ? <tr><td colSpan={4} className="empty-state"><p>Chưa có lớp nào</p></td></tr>
                  : classes.map(c => (
                    <tr key={c.id} style={{ cursor: "pointer", background: selected?.id === c.id ? "var(--primary-light)" : "" }}>
                      <td style={{ fontWeight: 500 }}>{c.name}</td>
                      <td>{c.currentStudents || 0}/{c.maxStudents}</td>
                      <td><span className={`badge ${c.status === "active" ? "badge-green" : "badge-yellow"}`}>
                        {c.status === "active" ? "Đang học" : "Chờ khai giảng"}
                      </span></td>
                      <td><button className="btn btn-primary btn-sm" onClick={() => viewStudents(c)}>Xem học viên</button></td>
                    </tr>
                  ))
                }
              </tbody>
            </table>
          )}
        </div>

        {selected && (
          <div className="section-card">
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 16 }}>
              <h3 className="section-title" style={{ margin: 0 }}>Học viên — {selected.name}</h3>
              <button className="btn btn-ghost btn-sm" onClick={() => setSelected(null)}>✕</button>
            </div>
            {students.length === 0
              ? <div className="empty-state"><p>Chưa có học viên</p></div>
              : students.map(s => (
                <div key={s.id} style={{ display: "flex", justifyContent: "space-between", padding: "10px 0", borderBottom: "1px solid var(--gray-100)", fontSize: "0.875rem" }}>
                  <span>ID: {s.userId}</span>
                  <span className={`badge ${s.status === "enrolled" ? "badge-green" : "badge-yellow"}`}>{s.status}</span>
                  <span style={{ color: "var(--gray-500)" }}>{s.progress || 0}%</span>
                </div>
              ))
            }
          </div>
        )}
      </div>
    </div>
  );
}
